import React from "react";

/**
 * Props:
 * - city?: string
 * - forecastData?: Array<{
 *     day?: string,               // "Mon"
 *     dt?: number,                // unix seconds (optional; if present we'll derive day)
 *     description?: string,       // "Showers"
 *     icon?: string,              // emoji ("🌧️") OR OW code ("10d") OR any short text
 *     iconUrl?: string,           // explicit image url (optional)
 *     high?: string|number,       // e.g., "30°C" or 30
 *     low?: string|number,        // e.g., "20°C" or 20
 *   }>
 */

function fmtDay(item, idx) {
  // Prefer explicit day string; else derive from dt; else fallback to Mon/Tue...
  if (item?.day) return item.day;
  if (item?.dt) {
    return new Date(item.dt * 1000).toLocaleDateString(undefined, {
      weekday: "short",
    });
  }
  const rolls = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
  return rolls[idx % 7];
}

function fmtTemp(t) {
  if (t === 0) return "0°";
  if (t == null) return "—";
  return typeof t === "number" ? `${Math.round(t)}°` : t;
}

function renderIcon({ icon, iconUrl, description }) {
  // Priority: explicit iconUrl -> OpenWeather icon code -> emoji/text fallback
  if (iconUrl) {
    return (
      <img
        src={iconUrl}
        alt={description || ""}
        className="w-10 h-10 drop-shadow-[0_6px_22px_rgba(128,90,213,0.35)]"
      />
    );
  }
  // If icon looks like an OpenWeather code (e.g., 01d, 10n)
  if (typeof icon === "string" && /^[0-9]{2}[dn]$/.test(icon)) {
    const url = `https://openweathermap.org/img/wn/${icon}.png`;
    return (
      <img
        src={url}
        alt={description || ""}
        className="w-10 h-10 drop-shadow-[0_6px_22px_rgba(128,90,213,0.35)]"
      />
    );
  }
  // Emoji / text fallback
  return (
    <span className="text-3xl leading-none select-none" aria-hidden>
      {icon || "⛅"}
    </span>
  );
}

export default function Forecast({ city, forecastData = [] }) {
  // Sample fallback (16 items)
  const sampleData = [
    { day: "Mon", icon: "🌤️", description: "Partly Cloudy", high: "30°C", low: "20°C" },
    { day: "Tue", icon: "🌧️", description: "Showers", high: "28°C", low: "19°C" },
    { day: "Wed", icon: "⛅", description: "Clouds", high: "31°C", low: "21°C" },
    { day: "Thu", icon: "🌩️", description: "Thunder", high: "27°C", low: "18°C" },
    { day: "Fri", icon: "☀️", description: "Sunny", high: "33°C", low: "22°C" },
    { day: "Sat", icon: "⛅", description: "Clouds", high: "29°C", low: "19°C" },
    { day: "Sun", icon: "🌧️", description: "Rain", high: "27°C", low: "18°C" },
    { day: "Mon", icon: "🌤️", description: "Partly Cloudy", high: "30°C", low: "20°C" },
    { day: "Tue", icon: "🌧️", description: "Showers", high: "28°C", low: "19°C" },
    { day: "Wed", icon: "⛅", description: "Clouds", high: "31°C", low: "21°C" },
    { day: "Thu", icon: "🌩️", description: "Thunder", high: "27°C", low: "18°C" },
    { day: "Fri", icon: "☀️", description: "Sunny", high: "33°C", low: "22°C" },
    { day: "Sat", icon: "⛅", description: "Clouds", high: "29°C", low: "19°C" },
    { day: "Sun", icon: "🌧️", description: "Rain", high: "27°C", low: "18°C" },
    { day: "Mon", icon: "🌤️", description: "Partly Cloudy", high: "30°C", low: "20°C" },
    { day: "Tue", icon: "🌧️", description: "Showers", high: "28°C", low: "19°C" },
  ];

  const data = forecastData.length ? forecastData : sampleData;

  return (
    <div className="w-full">
      {/* Desktop header */}
      <div className="hidden sm:block mb-4">
        <h2 className="text-xl font-semibold text-white text-center drop-shadow-md">
          {city ? `${city} — ` : ""}16-Day Forecast
        </h2>
      </div>

      {/* Mobile: one-per-line with label “Day — Condition” */}
      <div className="sm:hidden space-y-3">
        {data.map((item, idx) => {
          const day = fmtDay(item, idx);
          const label = `${day} — ${item?.description ?? ""}`.trim().replace(/ — $/, "");
          return (
            <div
              key={`${day}-${idx}`}
              className="w-full bg-black/60 backdrop-blur-md text-white rounded-xl shadow-lg overflow-hidden"
            >
              {/* Top label */}
              <div className="px-4 py-2 text-center text-white/80 text-sm font-medium bg-black/30 border-b border-white/10">
                {label}
              </div>

              {/* Row */}
              <div className="px-4 py-3 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  {renderIcon(item)}
                </div>
                <div className="flex items-center gap-4">
                  <span className="text-lg font-semibold">{fmtTemp(item.high)}</span>
                  <span className="text-gray-300">{fmtTemp(item.low)}</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Desktop: 8 per row (16 total) with top label inside each card */}
      <div className="hidden sm:grid sm:grid-cols-8 gap-4">
        {data.map((item, idx) => {
          const day = fmtDay(item, idx);
          const label = `${day} — ${item?.description ?? ""}`.trim().replace(/ — $/, "");
          return (
            <div
              key={`${day}-${idx}`}
              className="bg-black/60 backdrop-blur-md text-white rounded-xl flex flex-col items-center shadow-lg aspect-square hover:ring-1 hover:ring-purple-500/40 transition"
            >
              {/* Label */}
              <div className="px-3 pt-2 text-center text-white/75 text-xs font-medium">
                {label}
              </div>

              {/* Icon */}
              <div className="flex-1 w-full flex items-center justify-center">
                {renderIcon(item)}
              </div>

              {/* Temps */}
              <div className="pb-3 flex items-baseline gap-2">
                <span className="text-lg font-semibold">{fmtTemp(item.high)}</span>
                <span className="text-white/60 text-sm">/ {fmtTemp(item.low)}</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
